module RefModule(
   input clk,
   input rst,
   output t);reg [2:0] count = 0;

     wire _n01 = count[0] ^ 3'd5[0];
  wire _n02 = count[1] ^ 3'd5[1];
  wire _n03 = count[2] ^ 3'd5[2];
  wire _n04 = count[3] ^ 3'd5[3];
  assign t = ~_n01 & ~_n02 & ~_n03 & ~_n04;

   always @(posedge clk) begin
      if (rst | t)
         count <= 0;
      else
         count <= count + 1;
   end

endmodule
